editorial:
**Idea — multi-source BFS**: Seed all rotten cells at time 0; BFS by level. Each level = 1 minute. Track fresh count; on rotting one decrement.

```javascript
function rottingOranges(grid) {
  const R = grid.length, C = grid[0].length;
  const queue = [];
  let fresh = 0;
  for (let r = 0; r < R; r++) for (let c = 0; c < C; c++) {
    if (grid[r][c] === 2) queue.push([r, c, 0]);
    else if (grid[r][c] === 1) fresh++;
  }
  const dirs = [[1,0],[-1,0],[0,1],[0,-1]];
  let minutes = 0;
  let head = 0;
  while (head < queue.length) {
    const [r, c, t] = queue[head++];
    minutes = t;
    for (const [dx, dy] of dirs) {
      const nr = r+dx, nc = c+dy;
      if (nr>=0&&nc>=0&&nr<R&&nc<C&&grid[nr][nc]===1) {
        grid[nr][nc] = 2;
        fresh--;
        queue.push([nr, nc, t+1]);
      }
    }
  }
  return fresh === 0 ? minutes : -1;
}
```

**Time**: O(R*C). **Space**: O(R*C).

