editorial:
**Idea — BFS with wildcard buckets**: Pre-build `pattern → [words]`, e.g. `h*t → [hat, hit, hot]`. BFS from beginWord; each pop generates patterns of itself and walks to all bucket-mates.

```javascript
function wordLadderLength(beginWord, endWord, wordList) {
  const set = new Set(wordList);
  if (!set.has(endWord)) return 0;
  const buckets = new Map();
  for (const w of wordList) {
    for (let i = 0; i < w.length; i++) {
      const p = w.slice(0, i) + '*' + w.slice(i + 1);
      if (!buckets.has(p)) buckets.set(p, []);
      buckets.get(p).push(w);
    }
  }
  const visited = new Set([beginWord]);
  let queue = [beginWord], steps = 1;
  while (queue.length) {
    const next = [];
    for (const w of queue) {
      if (w === endWord) return steps;
      for (let i = 0; i < w.length; i++) {
        const p = w.slice(0, i) + '*' + w.slice(i + 1);
        for (const nb of (buckets.get(p) || [])) {
          if (!visited.has(nb)) { visited.add(nb); next.push(nb); }
        }
      }
    }
    queue = next;
    steps++;
  }
  return 0;
}
```

**Time**: O(N * L^2). **Space**: O(N * L^2).

