editorial:
**Idea — DFS uphill from each ocean**: Two boolean grids `pac` and `atl`. From every Pacific-edge cell, DFS to neighbours with equal-or-greater height, marking `pac`. Same for Atlantic. Cells true in both → answer.

```javascript
function pacificAtlantic(heights) {
  const R = heights.length, C = heights[0].length;
  const pac = Array.from({length: R}, () => new Array(C).fill(false));
  const atl = Array.from({length: R}, () => new Array(C).fill(false));
  const dirs = [[1,0],[-1,0],[0,1],[0,-1]];
  function dfs(r, c, vis) {
    vis[r][c] = true;
    for (const [dx, dy] of dirs) {
      const nr = r+dx, nc = c+dy;
      if (nr<0||nc<0||nr>=R||nc>=C||vis[nr][nc]) continue;
      if (heights[nr][nc] < heights[r][c]) continue;
      dfs(nr, nc, vis);
    }
  }
  for (let r = 0; r < R; r++) { dfs(r, 0, pac); dfs(r, C-1, atl); }
  for (let c = 0; c < C; c++) { dfs(0, c, pac); dfs(R-1, c, atl); }
  const out = [];
  for (let r = 0; r < R; r++) for (let c = 0; c < C; c++) if (pac[r][c] && atl[r][c]) out.push([r, c]);
  return out;
}
```

**Time**: O(R*C). **Space**: O(R*C).

