editorial:
**Idea — Prim's MST (O(n^2) array version)**: Maintain `minDist[i]` = current cheapest edge cost from any tree node to `i`. Repeatedly pick the unvisited node with smallest `minDist`, add it, then relax its neighbours.

```javascript
function minCostConnectPoints(points) {
  const n = points.length;
  if (n <= 1) return 0;
  const inTree = new Array(n).fill(false);
  const minDist = new Array(n).fill(Infinity);
  minDist[0] = 0;
  let total = 0;
  for (let step = 0; step < n; step++) {
    let u = -1;
    for (let i = 0; i < n; i++) {
      if (!inTree[i] && (u === -1 || minDist[i] < minDist[u])) u = i;
    }
    inTree[u] = true;
    total += minDist[u];
    for (let v = 0; v < n; v++) {
      if (!inTree[v]) {
        const d = Math.abs(points[u][0]-points[v][0]) + Math.abs(points[u][1]-points[v][1]);
        if (d < minDist[v]) minDist[v] = d;
      }
    }
  }
  return total;
}
```

**Time**: O(n^2). **Space**: O(n).

