**Idea — BFS 2-coloring**: For each unvisited node, BFS assigning alternating colors 0/1. If a neighbour is already colored the same as current node, not bipartite.

```javascript
function isBipartite(graph) {
  const n = graph.length;
  const color = new Array(n).fill(-1);
  for (let s = 0; s < n; s++) {
    if (color[s] !== -1) continue;
    color[s] = 0;
    const queue = [s];
    let head = 0;
    while (head < queue.length) {
      const u = queue[head++];
      for (const v of graph[u]) {
        if (color[v] === -1) {
          color[v] = 1 - color[u];
          queue.push(v);
        } else if (color[v] === color[u]) {
          return false;
        }
      }
    }
  }
  return true;
}
```

**Time**: O(V+E). **Space**: O(V).

