editorial:
**Idea — sweep and BFS**: For every unvisited vertex, BFS to gather a component. Sort the component, push it. After all components are gathered, sort them by their first element (already minimum due to internal sort).

```javascript
function listAllComponents(n, edges) {
  const adj = Array.from({length: n}, () => []);
  for (const [u, v] of edges) { adj[u].push(v); adj[v].push(u); }
  const visited = new Array(n).fill(false);
  const comps = [];
  for (let s = 0; s < n; s++) {
    if (visited[s]) continue;
    const comp = [];
    const stack = [s];
    visited[s] = true;
    while (stack.length) {
      const u = stack.pop();
      comp.push(u);
      for (const v of adj[u]) if (!visited[v]) { visited[v] = true; stack.push(v); }
    }
    comp.sort((a, b) => a - b);
    comps.push(comp);
  }
