**Idea — multi-source BFS from land**: Push every land cell at distance 0; expand layer by layer. The last distance reached is the answer.

```javascript
function maxDistanceFromLand(grid) {
  const n = grid.length;
  const queue = [];
  for (let r = 0; r < n; r++) for (let c = 0; c < n; c++) if (grid[r][c] === 1) queue.push([r, c]);
  if (queue.length === 0 || queue.length === n * n) return -1;
  const dist = Array.from({length: n}, () => new Array(n).fill(-1));
  for (const [r, c] of queue) dist[r][c] = 0;
  const dirs = [[1,0],[-1,0],[0,1],[0,-1]];
  let head = 0, best = 0;
  while (head < queue.length) {
    const [r, c] = queue[head++];
    for (const [dx, dy] of dirs) {
      const nr = r+dx, nc = c+dy;
      if (nr<0||nc<0||nr>=n||nc>=n||dist[nr][nc]!==-1) continue;
      dist[nr][nc] = dist[r][c] + 1;
      best = Math.max(best, dist[nr][nc]);
      queue.push([nr, nc]);
    }
  }
  return best;
}
```

**Time**: O(n^2). **Space**: O(n^2).

