editorial:
**Idea — degree + connectivity check**: Count degrees. If isolated nodes are ignored, the edges must all live in one connected component. Then the count of odd-degree vertices must be 0 (Eulerian circuit) or 2 (Eulerian path).

```javascript
function hasEulerianPath(n, edges) {
  if (edges.length === 0) return true;
  const adj = Array.from({length: n}, () => []);
  const deg = new Array(n).fill(0);
  for (const [u, v] of edges) { adj[u].push(v); adj[v].push(u); deg[u]++; deg[v]++; }
  let odd = 0;
  for (let i = 0; i < n; i++) if (deg[i] % 2 === 1) odd++;
  if (odd !== 0 && odd !== 2) return false;
  let start = -1;
  for (let i = 0; i < n; i++) if (deg[i] > 0) { start = i; break; }
  const visited = new Array(n).fill(false);
  const stack = [start];
  visited[start] = true;
  while (stack.length) {
    const u = stack.pop();
    for (const v of adj[u]) if (!visited[v]) { visited[v] = true; stack.push(v); }
  }
  for (let i = 0; i < n; i++) if (deg[i] > 0 && !visited[i]) return false;
  return true;
}
```

**Time**: O(V+E). **Space**: O(V+E).

